namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public int InstructorId { get; set; }
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{2}\d{6}$", ErrorMessage = "Student ID must be 2 uppercase letters followed by 6 digits (e.g., CS123456).")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    Department? GetDepartment(int id);
    List<Course> GetCourses(string? searchTerm = null, int? departmentId = null);
    List<Course> GetFeaturedCourses();
    Course? GetCourse(int id);
    Instructor? GetInstructor(int id);
    bool SubmitEnrollmentRequest(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics including statistics and data analysis." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Literature, writing, and language studies." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events, civilizations, and their impact on the modern world." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor of Computer Science", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers in top-tier journals and holds 3 patents in neural network architectures.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Wilson", Title = "Associate Professor of Mathematics", Bio = "Dr. Wilson's research focuses on applied statistics and probability theory. He has 15 years of teaching experience and received the Distinguished Teaching Award in 2023.", Email = "j.wilson@university.edu" },
            new() { Id = 3, Name = "Prof. Maria Rodriguez", Title = "Professor of English", Bio = "Prof. Rodriguez is a published novelist and literary critic specializing in contemporary American fiction and creative writing pedagogy.", Email = "m.rodriguez@university.edu" },
            new() { Id = 4, Name = "Dr. Michael Park", Title = "Associate Professor of Physics", Bio = "Dr. Park conducts research in quantum mechanics and particle physics. He previously worked at CERN and brings real-world research experience to the classroom.", Email = "m.park@university.edu" },
            new() { Id = 5, Name = "Dr. Emily Thompson", Title = "Professor of History", Bio = "Dr. Thompson is a specialist in modern European history with a focus on the World Wars. She has authored three books and frequently contributes to historical documentaries.", Email = "e.thompson@university.edu" },
            new() { Id = 6, Name = "Dr. Robert Kim", Title = "Assistant Professor of Computer Science", Bio = "Dr. Kim specializes in software engineering and distributed systems. Before academia, he spent 10 years as a senior engineer at major tech companies.", Email = "r.kim@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Topics include variables, control structures, functions, and basic data structures. No prior programming experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, InstructorId = 1, IsFeatured = true },
            new() { Id = 2, Code = "CS201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques (sorting, searching, dynamic programming). Prerequisites: CS101.", Credits = 4, Schedule = "Tue/Thu 10:00–11:50 AM", DepartmentId = 1, InstructorId = 6, IsFeatured = true },
            new() { Id = 3, Code = "CS301", Title = "Software Engineering", Description = "Principles and practices of software development including agile methodologies, version control, testing, and project management. Includes a team-based capstone project.", Credits = 4, Schedule = "Mon/Wed 2:00–3:50 PM", DepartmentId = 1, InstructorId = 6, IsFeatured = false },
            new() { Id = 4, Code = "MATH101", Title = "Calculus I", Description = "Introduction to differential calculus including limits, derivatives, and their applications. Covers techniques of differentiation and introductory integration.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, InstructorId = 2, IsFeatured = false },
            new() { Id = 5, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations. Essential for advanced work in science and engineering.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, InstructorId = 2, IsFeatured = true },
            new() { Id = 6, Code = "ENG101", Title = "College Writing", Description = "Develop critical thinking and writing skills through essay composition, peer review, and revision. Emphasis on argumentation and evidence-based writing.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, InstructorId = 3, IsFeatured = false },
            new() { Id = 7, Code = "ENG205", Title = "Creative Writing Workshop", Description = "Workshop-based course in fiction and poetry writing. Students produce original works and participate in peer critique sessions.", Credits = 3, Schedule = "Wed 6:00–8:50 PM", DepartmentId = 3, InstructorId = 3, IsFeatured = true },
            new() { Id = 8, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions. Co-requisite: MATH101.", Credits = 4, Schedule = "Tue/Thu 8:00–9:20 AM + Lab Fri 1:00–3:50 PM", DepartmentId = 4, InstructorId = 4, IsFeatured = false },
            new() { Id = 9, Code = "PHYS202", Title = "Modern Physics", Description = "Introduction to special relativity, quantum mechanics, atomic structure, and nuclear physics. Prerequisites: PHYS101, MATH201.", Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", DepartmentId = 4, InstructorId = 4, IsFeatured = false },
            new() { Id = 10, Code = "HIST101", Title = "World History to 1500", Description = "Survey of major civilizations and events from prehistory through the late medieval period. Covers political, social, and cultural developments across the globe.", Credits = 3, Schedule = "Tue/Thu 2:00–3:20 PM", DepartmentId = 5, InstructorId = 5, IsFeatured = false },
            new() { Id = 11, Code = "HIST301", Title = "The World Wars", Description = "In-depth analysis of World War I and World War II, examining causes, key battles, home front experiences, and lasting geopolitical impacts.", Credits = 3, Schedule = "Mon/Wed 3:00–4:20 PM", DepartmentId = 5, InstructorId = 5, IsFeatured = true },
            new() { Id = 12, Code = "CS401", Title = "Artificial Intelligence", Description = "Survey of AI techniques including search algorithms, knowledge representation, machine learning, natural language processing, and computer vision. Prerequisites: CS201, MATH201.", Credits = 4, Schedule = "Tue/Thu 3:00–4:50 PM", DepartmentId = 1, InstructorId = 1, IsFeatured = true },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        if (departmentId.HasValue && departmentId.Value > 0)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public Instructor? GetInstructor(int id) => _instructors.FirstOrDefault(i => i.Id == id);

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return GetCourse(request.CourseId) is not null;
    }
}

