@page "/courses"
@inject ICatalogService CatalogService

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search" placeholder="Search by title, code, or description..." />
    </div>
    <div class="col-md-4">
        <label for="departmentId" class="form-label">Department</label>
        <select class="form-select" id="departmentId" name="departmentId">
            <option value="">All Departments</option>
            @foreach (var dept in _departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (_courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in _courses)
                {
                    var dept = CatalogService.GetDepartment(course.DepartmentId);
                    <tr>
                        <td>@course.Code</td>
                        <td>@course.Title</td>
                        <td>@dept?.Name</td>
                        <td>@course.Credits</td>
                        <td>@course.Schedule</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    private List<Course> _courses = new();
    private List<Department> _departments = new();

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();
        _courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@inject ICatalogService CatalogService

@if (_course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-secondary">Back to Catalog</a>
}
else
{
    <PageTitle>@_course.Code — @_course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.Code</li>
        </ol>
    </nav>

    <h1>@_course.Code — @_course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@_course.Description</p>

            <h3 class="mt-4">Schedule</h3>
            <p><strong>@_course.Schedule</strong></p>

            <h3 class="mt-4">Credits</h3>
            <p><span class="badge bg-primary fs-6">@_course.Credits credits</span></p>

            <div class="mt-4">
                <a href="enroll?courseId=@_course.Id" class="btn btn-success">Request Enrollment</a>
                <a href="courses" class="btn btn-outline-secondary ms-2">Back to Catalog</a>
            </div>
        </div>
        <div class="col-md-4">
            @if (_instructor is not null)
            {
                <div class="card">
                    <div class="card-body">
                        <h4 class="card-title">Instructor</h4>
                        <h5>@_instructor.Name</h5>
                        <p class="text-muted">@_instructor.Title</p>
                        <p>@_instructor.Bio</p>
                        <p><strong>Email:</strong> <a href="mailto:@_instructor.Email">@_instructor.Email</a></p>
                    </div>
                </div>
            }

            @if (_department is not null)
            {
                <div class="card mt-3">
                    <div class="card-body">
                        <h5 class="card-title">Department</h5>
                        <p>@_department.Name</p>
                        <a href="courses?departmentId=@_department.Id" class="btn btn-sm btn-outline-secondary">
                            View all @_department.Code courses
                        </a>
                    </div>
                </div>
            }
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? _course;
    private Instructor? _instructor;
    private Department? _department;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourse(Id);
        if (_course is not null)
        {
            _instructor = CatalogService.GetInstructor(_course.InstructorId);
            _department = CatalogService.GetDepartment(_course.DepartmentId);
        }
    }
}

@page "/enroll"
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Submit Enrollment Request</h1>
<p>Complete the form below to request enrollment in a course.</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Your enrollment request for <strong>@_selectedCourseName</strong> has been submitted successfully. You will receive confirmation via your university email.</p>
        <hr>
        <a href="courses" class="btn btn-outline-success">Browse More Courses</a>
        <a href="enroll" class="btn btn-success ms-2">Submit Another Request</a>
    </div>
}
else
{
    <div class="row">
        <div class="col-md-8 col-lg-6">
            <EditForm Model="Model" FormName="enrollment" method="post" OnValidSubmit="HandleSubmit">
                <DataAnnotationsValidator />
                <AntiforgeryToken />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                    <ValidationMessage For="() => Model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g., CS123456" />
                    <ValidationMessage For="() => Model.StudentId" class="text-danger" />
                    <div class="form-text">Format: 2 uppercase letters followed by 6 digits.</div>
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">-- Select a course --</option>
                        @foreach (var course in _courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> _courses = new();
    private bool _submitted;
    private string _selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(Model.CourseId);
        if (course is not null)
        {
            _selectedCourseName = $"{course.Code} — {course.Title}";
            CatalogService.SubmitEnrollmentRequest(Model);
            _submitted = true;
        }
    }
}

